   325→                            "<{}>",
   326→                            std::iter::repeat("'_")
   327→                                .take(counts.lifetimes)
   328→                                .chain(std::iter::repeat("_").take(counts.types + counts.consts))
   329→                                .collect::<Vec<_>>()
   330→                                .join(", ")
   331→                        );
   332→                    }
   333→                }
